// Find the original appointmentId from anywhere in the failed workflow's run data.
// We scan all node outputs for a body.appointmentId or top-level appointmentId,
// so this works regardless of how the webhook node is named in Workflow #5.

const input = $input.first().json;
const runData = input.execution?.data?.resultData?.runData ?? {};

let appointmentId = null;
let practitionerId = null;

function findIds(obj, depth = 0) {
  if (!obj || typeof obj !== 'object' || depth > 8) return;
  if (obj.appointmentId && !appointmentId) appointmentId = obj.appointmentId;
  if (obj.practitionerId && !practitionerId) practitionerId = obj.practitionerId;
  for (const key of Object.keys(obj)) {
    findIds(obj[key], depth + 1);
  }
}

findIds(runData);

const errorMessage = input.execution?.error?.message ?? 'Unknown error';
const lastNode = input.execution?.lastNodeExecuted ?? 'unknown';

return [{
  json: {
    appointmentId,
    practitionerId,
    errorMessage,
    lastNode,
    canPatch: appointmentId !== null,
    // Debug: include node names found so we can see what's available
    nodesInRunData: Object.keys(runData),
  },
}];
